# Tunix standalone US console map, compatible with Linux loadkeys syntax.
charset "UTF-8"
keymaps 0-7
alt_is_meta
keycode 1 = Escape
keycode 2 = one exclam
keycode 3 = two at
keycode 4 = three numbersign
keycode 5 = four dollar
keycode 6 = five percent
keycode 7 = six asciicircum
keycode 8 = seven ampersand
keycode 9 = eight asterisk
keycode 10 = nine parenleft
keycode 11 = zero parenright
keycode 12 = minus underscore
keycode 13 = equal plus
keycode 14 = Delete
keycode 15 = Tab
keycode 16 = +q +Q
keycode 17 = +w +W
keycode 18 = +e +E euro
keycode 19 = +r +R
keycode 20 = +t +T
keycode 21 = +y +Y
keycode 22 = +u +U
keycode 23 = +i +I
keycode 24 = +o +O
keycode 25 = +p +P
keycode 26 = bracketleft braceleft
keycode 27 = bracketright braceright
keycode 28 = Return
keycode 30 = +a +A
keycode 31 = +s +S
keycode 32 = +d +D
keycode 33 = +f +F
keycode 34 = +g +G
keycode 35 = +h +H
keycode 36 = +j +J
keycode 37 = +k +K
keycode 38 = +l +L
keycode 39 = semicolon colon
keycode 40 = apostrophe quotedbl
keycode 41 = grave asciitilde
keycode 43 = backslash bar
keycode 44 = +z +Z
keycode 45 = +x +X
keycode 46 = +c +C
keycode 47 = +v +V
keycode 48 = +b +B
keycode 49 = +n +N
keycode 50 = +m +M
keycode 51 = comma less
keycode 52 = period greater
keycode 53 = slash question
keycode 57 = space
control keycode 57 = nul
keycode 86 = less greater bar
